					error: "Fake runner callback was not applied.",
					prompt: {
						instructionPath: instructions.instructionPath,
						length: promptLength,
						preview: promptPreview,
						eventId: promptEvent.id,
					},
					startResult,
					callbackResult,
				},
				{ status: 409 },
